+/// A contiguous span of dirty cells to update on the GPU.
+#[derive(Debug, Clone)]
+pub struct CellPatch {
+    /// Linear offset into the cell grid (row * cols + col).
+    pub offset: u32,
+    /// Cell data for each cell in the span.
+    pub cells: Vec<CellData>,
+}
