+// ---------------------------------------------------------------------------
+// WGSL shader (inline)
+// ---------------------------------------------------------------------------
+
+#[cfg(target_arch = "wasm32")]
+const CELL_SHADER_WGSL: &str = r#"
+struct Uniforms {
+    // (viewport_width, viewport_height, cell_width, cell_height)
+    viewport: vec4<f32>,
+    // (cols, rows, 0, 0)
+    grid: vec4<u32>,
+}
+
+struct CellData {
+    bg_rgba: u32,
