+
+            // Shader module.
+            let shader = device.create_shader_module(wgpu::ShaderModuleDescriptor {
+                label: Some("cell_shader"),
+                source: wgpu::ShaderSource::Wgsl(CELL_SHADER_WGSL.into()),
