+            // Rebuild cell buffer for new grid size.
+            let cell_count = (cols as usize) * (rows as usize);
+            self.cells_cpu.resize(cell_count, CellData::EMPTY);
+            let cell_bytes = cells_to_bytes(&self.cells_cpu);
