+            self.cell_buffer = self.device.create_buffer(&wgpu::BufferDescriptor {
+                label: Some("cells"),
+                size: cell_bytes.len() as u64,
+                usage: wgpu::BufferUsages::STORAGE | wgpu::BufferUsages::COPY_DST,
+                mapped_at_creation: false,
+            });
