+                // Upload only the dirty range to the GPU.
+                let byte_offset = (start as u64) * (CELL_DATA_BYTES as u64);
+                let bytes = cells_to_bytes(cells);
+                self.queue
+                    .write_buffer(&self.cell_buffer, byte_offset, &bytes);
+                dirty += count as u32;
+            }
+            dirty
+        }
