+        /// Encode and submit one render frame.
+        pub fn render_frame(&self) -> Result<FrameStats, RendererError> {
+            let output = self
+                .surface
+                .get_current_texture()
+                .map_err(|e| RendererError::SurfaceError(e.to_string()))?;
+
+            let view = output
+                .texture
+                .create_view(&wgpu::TextureViewDescriptor::default());
