+                pass.set_pipeline(&self.pipeline);
+                pass.set_bind_group(0, &self.bind_group, &[]);
+                // 6 vertices per cell (2 triangles), instanced per cell.
+                pass.draw(0..6, 0..instance_count);
+            }
